// Lê config
const cfg = $json;
const backendUrl = cfg.backend_url;
const apiKey = cfg.api_key;
const sessionIds = cfg.session_ids || [];
const sources = Array.isArray(cfg.sources) ? cfg.sources : [];
const userAgent = cfg.user_agent || 'Mozilla/5.0';
const maxPerSessionDay = parseInt(cfg.max_per_session_day||'0')||0;
const startTime = (cfg.start_time||'')||null;
const endTime = (cfg.end_time||'')||null;
const perSourceLimit = Math.max(0, parseInt(cfg.per_source_limit||'0')||0);
const globalLimit = Math.max(0, parseInt(cfg.global_limit||'0')||0);
const chunkSize = Math.max(1, parseInt(cfg.chunk_size||'50')||50);
const blacklist = new Set((cfg.blacklist_domains||[]).map((x)=>String(x).toLowerCase()));

function hostname(url){ try{ return new URL(url).hostname.toLowerCase(); }catch{ return ''; } }
function extractLinks(text){ const re=/https?:\/\/chat\.whatsapp\.com\/[A-Za-z0-9_-]+/g; return Array.from(new Set((text.match(re)||[]))); }
async function fetchText(url){ const res = await this.helpers.httpRequest({ method:'GET', url, json:false, headers: { 'User-Agent': userAgent } }); return typeof res==='string'?res:(res.body||''); }

let allLinks = []; const report = [];
for (const url of sources){
  try {
    const html = await fetchText.call(this, url);
    let links = extractLinks(html);
    // Filtro por blacklist
    links = links.filter(l => !blacklist.has(hostname(l)));
    if (perSourceLimit>0 && links.length>perSourceLimit) links = links.slice(0, perSourceLimit);
    allLinks.push(...links);
    report.push({ url, found: links.length });
  } catch(e){
    report.push({ url, error: (e&&e.message)?e.message:String(e) });
  }
}
// Dedup global
allLinks = Array.from(new Set(allLinks));
if (globalLimit>0 && allLinks.length>globalLimit) allLinks = allLinks.slice(0, globalLimit);

return [{ json: { backendUrl, apiKey, sessionIds, startTime, endTime, maxPerSessionDay, chunkSize, links: allLinks, report } }];

const { backendUrl, apiKey, sessionIds, startTime, endTime, maxPerSessionDay, chunkSize, links, report } = $json;

function chunk(arr, size){ const out=[]; for(let i=0;i<arr.length;i+=size){ out.push(arr.slice(i,i+size)); } return out; }

async function postJoin(batch){ const body = { session_ids: sessionIds, invite_links: batch, max_per_session_day: maxPerSessionDay, start_time: startTime, end_time: endTime, source: 'scraper' }; return this.helpers.httpRequest({ method:'POST', url: `${backendUrl}/api/integrations/join-groups`, headers: { 'X-API-Key': apiKey, 'Content-Type':'application/json' }, body, json:true }); }

let queuedTotal = 0; const posts = []; const chunks = chunk(links||[], Math.max(1, chunkSize));
for (const c of chunks){
  try{ const r = await postJoin.call(this, c); queuedTotal += (r&&r.queued)?r.queued:0; posts.push({ batchSize: c.length, queued: r.queued||0 }); }
  catch(e){ posts.push({ batchSize: c.length, error: (e&&e.message)?e.message:String(e) }); }
}

return [{ json: { queuedTotal, batches: posts, scraped: (links||[]).length, report } }];
